import{_ as t,o,c as n,a2 as i}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Installation","description":"Nonaki Plugin Installation","frontmatter":{"title":"Installation","description":"Nonaki Plugin Installation","weight":10,"extra":{"order":10},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/installation"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/installation"}],["meta",{"property":"og:title","content":"Installation"}],["meta",{"property":"og:description","content":"Nonaki Plugin Installation"}],["meta",{"name":"twitter:title","content":"Installation"}],["meta",{"name":"twitter:description","content":"Nonaki Plugin Installation"}]]},"headers":[],"relativePath":"docs/nonaki/installation.md","filePath":"docs/nonaki/installation.md"}'),e={name:"docs/nonaki/installation.md"};function l(r,a,s,d,c,h){return o(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="plugin-installation" tabindex="-1">Plugin Installation <a class="header-anchor" href="#plugin-installation" aria-label="Permalink to &quot;Plugin Installation&quot;">​</a></h1><p>You can install the plugin either through the WordPress dashboard (recommended) or via FTP.</p><hr><h2 id="before-installation" tabindex="-1">Before Installation <a class="header-anchor" href="#before-installation" aria-label="Permalink to &quot;Before Installation&quot;">​</a></h2><p>Make sure your server meets the minimum <a href="/docs/nonaki/">system requirements</a> and download the plugin file from your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a>.</p><h3 id="install-through-wordpress-dashboard" tabindex="-1">Install through WordPress Dashboard <a class="header-anchor" href="#install-through-wordpress-dashboard" aria-label="Permalink to &quot;Install through WordPress Dashboard&quot;">​</a></h3><ol><li>Visit WordPress dashboard → <strong>Plugins</strong> and click <code>Add New</code>, then <code>Upload Plugin</code></li><li>Click <code>Choose File</code>, select <code>nonaki.zip</code> and click <code>Install Now</code></li><li>Activate the plugin</li></ol><h3 id="install-via-ftp" tabindex="-1">Install via FTP <a class="header-anchor" href="#install-via-ftp" aria-label="Permalink to &quot;Install via FTP&quot;">​</a></h3><ol><li>Log in to your server using an FTP client, cPanel, or similar</li><li>Navigate to the <code>plugins</code> directory in your WordPress root</li><li>Upload <code>nonaki.zip</code> and unzip it — you should have a <code>nonaki</code> directory in <code>plugins</code></li><li>Remove the <code>nonaki.zip</code> file</li><li>Visit WordPress dashboard → <strong>Plugins</strong> and activate the plugin</li></ol>',9)])])}const m=t(e,[["render",l]]);export{p as __pageData,m as default};
